// Some portions generated by Co-Pilot
import { describe, it, expect, vi, beforeEach } from "vitest";
import fs from "fs";
import {
  processMarkdown,
  compileMdxToHtml,
  getBlogPosts,
  mdxOptions,
} from "../markdown";

// Mock fs module
vi.mock("fs", () => ({
  default: {
    readdirSync: vi.fn(),
    readFileSync: vi.fn(),
    existsSync: vi.fn(),
  },
  readdirSync: vi.fn(),
  readFileSync: vi.fn(),
  existsSync: vi.fn(),
}));

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const mockedFs = fs as any;

describe("markdown utilities", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe("mdxOptions", () => {
    it("should export mdxOptions with remarkGfm plugin", () => {
      expect(mdxOptions).toBeDefined();
      expect(mdxOptions.mdxOptions).toBeDefined();
      expect(mdxOptions.mdxOptions.remarkPlugins).toHaveLength(1);
    });
  });

  describe("processMarkdown", () => {
    it("should convert basic markdown to HTML", async () => {
      const result = await processMarkdown("# Hello World");
      expect(result).toContain("<h1>Hello World</h1>");
    });

    it("should convert paragraphs", async () => {
      const result = await processMarkdown("This is a paragraph.");
      expect(result).toContain("<p>This is a paragraph.</p>");
    });

    it("should convert bold and italic text", async () => {
      const result = await processMarkdown("**bold** and *italic*");
      expect(result).toContain("<strong>bold</strong>");
      expect(result).toContain("<em>italic</em>");
    });

    it("should convert links", async () => {
      const result = await processMarkdown("[Adoptium](https://adoptium.net)");
      expect(result).toContain('<a href="https://adoptium.net">Adoptium</a>');
    });

    it("should convert inline code", async () => {
      const result = await processMarkdown("Use `java -version` to check");
      expect(result).toContain("<code>java -version</code>");
    });

    it("should convert code blocks", async () => {
      const result = await processMarkdown("```bash\njava -version\n```");
      expect(result).toContain("<code");
      expect(result).toContain("java -version");
    });

    it("should convert unordered lists", async () => {
      const result = await processMarkdown("- item 1\n- item 2\n- item 3");
      expect(result).toContain("<ul>");
      expect(result).toContain("<li>item 1</li>");
      expect(result).toContain("<li>item 2</li>");
      expect(result).toContain("<li>item 3</li>");
    });

    it("should convert ordered lists", async () => {
      const result = await processMarkdown("1. first\n2. second\n3. third");
      expect(result).toContain("<ol>");
      expect(result).toContain("<li>first</li>");
    });

    it("should convert images", async () => {
      const result = await processMarkdown("![alt text](/images/test.png)");
      expect(result).toContain("<img");
      expect(result).toContain('src="/images/test.png"');
      expect(result).toContain('alt="alt text"');
    });

    it("should support GFM tables", async () => {
      const markdown = `| Header 1 | Header 2 |\n| --- | --- |\n| Cell 1 | Cell 2 |`;
      const result = await processMarkdown(markdown);
      expect(result).toContain("<table>");
      expect(result).toContain("<th>Header 1</th>");
      expect(result).toContain("<td>Cell 1</td>");
    });

    it("should support GFM strikethrough", async () => {
      const result = await processMarkdown("~~deleted~~");
      expect(result).toContain("<del>deleted</del>");
    });

    it("should support GFM task lists", async () => {
      const result = await processMarkdown("- [x] done\n- [ ] todo");
      expect(result).toContain('type="checkbox"');
    });

    it("should handle empty content", async () => {
      const result = await processMarkdown("");
      expect(result).toBe("");
    });

    it("should convert blockquotes", async () => {
      const result = await processMarkdown("> This is a quote");
      expect(result).toContain("<blockquote>");
      expect(result).toContain("This is a quote");
    });

    it("should convert multiple heading levels", async () => {
      const markdown = "# H1\n## H2\n### H3\n#### H4";
      const result = await processMarkdown(markdown);
      expect(result).toContain("<h1>H1</h1>");
      expect(result).toContain("<h2>H2</h2>");
      expect(result).toContain("<h3>H3</h3>");
      expect(result).toContain("<h4>H4</h4>");
    });
  });

  describe("compileMdxToHtml", () => {
    it("should convert markdown to HTML", async () => {
      const result = await compileMdxToHtml("# Hello World");
      expect(result).toContain("<h1");
      expect(result).toContain("Hello World");
    });

    it("should add slug IDs to headings", async () => {
      const result = await compileMdxToHtml("## Getting Started");
      expect(result).toContain('id="getting-started"');
    });

    it("should add autolink anchors to headings", async () => {
      const result = await compileMdxToHtml("## Installation Guide");
      expect(result).toContain('id="installation-guide"');
      expect(result).toContain("<a");
      expect(result).toContain('href="#installation-guide"');
    });

    it("should support GFM tables", async () => {
      const markdown = `| Feature | Status |\n| --- | --- |\n| SSR | Supported |`;
      const result = await compileMdxToHtml(markdown);
      expect(result).toContain("<table>");
      expect(result).toContain("<th>Feature</th>");
      expect(result).toContain("<td>Supported</td>");
    });

    it("should preserve raw HTML with allowDangerousHtml", async () => {
      const markdown = `<div class="custom">Custom HTML</div>`;
      const result = await compileMdxToHtml(markdown);
      expect(result).toContain('class="custom"');
      expect(result).toContain("Custom HTML");
    });

    it("should handle multiple headings with unique slugs", async () => {
      const markdown = "## First Section\n\nContent\n\n## Second Section";
      const result = await compileMdxToHtml(markdown);
      expect(result).toContain('id="first-section"');
      expect(result).toContain('id="second-section"');
    });

    it("should convert inline code", async () => {
      const result = await compileMdxToHtml("Run `npm install` to begin");
      expect(result).toContain("<code>npm install</code>");
    });

    it("should convert links", async () => {
      const result = await compileMdxToHtml("[docs](/docs)");
      expect(result).toContain('<a href="/docs">docs</a>');
    });

    it("should handle empty content", async () => {
      const result = await compileMdxToHtml("");
      expect(result).toBe("");
    });

    it("should support GFM strikethrough", async () => {
      const result = await compileMdxToHtml("~~removed~~");
      expect(result).toContain("<del>removed</del>");
    });
  });

  describe("getBlogPosts", () => {
    it("should call getMDXData with the correct blog directory", () => {
      mockedFs.readdirSync.mockReturnValue([]);

      const posts = getBlogPosts();
      expect(posts).toEqual([]);
      expect(mockedFs.readdirSync).toHaveBeenCalled();
    });

    it("should parse blog posts with frontmatter", () => {
      // Mock directory listing with one blog post directory
      mockedFs.readdirSync.mockReturnValue([
        { name: "test-post", isDirectory: () => true, isFile: () => false },
      ]);
      mockedFs.existsSync.mockReturnValue(true);
      mockedFs.readFileSync.mockReturnValue(
        `---
title: Test Post
date: "2026-04-28"
author: Test Author
description: A test post
tags:
  - test
  - example
---

# Test Content

This is the body.`,
      );

      const posts = getBlogPosts();
      expect(posts).toHaveLength(1);
      expect(posts[0].metadata.title).toBe("Test Post");
      expect(posts[0].metadata.date).toBe("2026-04-28");
      expect(posts[0].metadata.author).toBe("Test Author");
      expect(posts[0].metadata.description).toBe("A test post");
      expect(posts[0].metadata.tags).toEqual(["test", "example"]);
      expect(posts[0].slug).toBe("test-post");
      expect(posts[0].year).toBe("2026");
      expect(posts[0].month).toBe("04");
      expect(posts[0].readingTime).toBeGreaterThan(0);
    });

    it("should handle posts with single tag as string", () => {
      mockedFs.readdirSync.mockReturnValue([
        { name: "single-tag", isDirectory: () => true, isFile: () => false },
      ]);
      mockedFs.existsSync.mockReturnValue(true);
      mockedFs.readFileSync.mockReturnValue(
        `---
title: Single Tag Post
date: "2026-01-15"
author: Author
description: Post with single tag
tags: solo-tag
---

Content here.`,
      );

      const posts = getBlogPosts();
      expect(posts[0].metadata.tags).toEqual(["solo-tag"]);
    });

    it("should handle posts without date, defaulting to current date", () => {
      mockedFs.readdirSync.mockReturnValue([
        { name: "no-date", isDirectory: () => true, isFile: () => false },
      ]);
      mockedFs.existsSync.mockReturnValue(true);
      mockedFs.readFileSync.mockReturnValue(
        `---
title: No Date Post
author: Author
description: Missing date
---

Content.`,
      );

      const posts = getBlogPosts();
      expect(posts[0].year).toBeDefined();
      expect(posts[0].month).toBeDefined();
      expect(posts[0].year.length).toBe(4);
      expect(posts[0].month.length).toBe(2);
    });

    it("should handle direct .md files (not in directories)", () => {
      mockedFs.readdirSync.mockReturnValue([
        {
          name: "direct-post.md",
          isDirectory: () => false,
          isFile: () => true,
        },
      ]);
      mockedFs.readFileSync.mockReturnValue(
        `---
title: Direct Post
date: "2026-03-10"
author: Author
description: A direct md file
---

Content.`,
      );

      const posts = getBlogPosts();
      expect(posts).toHaveLength(1);
      expect(posts[0].slug).toBe("direct-post");
    });

    it("should skip directories without index.md", () => {
      mockedFs.readdirSync.mockReturnValue([
        { name: "no-index-dir", isDirectory: () => true, isFile: () => false },
      ]);
      mockedFs.existsSync.mockReturnValue(false);

      const posts = getBlogPosts();
      expect(posts).toHaveLength(0);
    });

    it("should skip non-md files", () => {
      mockedFs.readdirSync.mockReturnValue([
        { name: "readme.txt", isDirectory: () => false, isFile: () => true },
        { name: "image.png", isDirectory: () => false, isFile: () => true },
      ]);

      const posts = getBlogPosts();
      expect(posts).toHaveLength(0);
    });
  });
});
